#include <stdio.h>
#include <stdbool.h>

#define MAX_N 200

void dfs(int connectionMatrix[][MAX_N], bool visited[], int n, int city) {
    visited[city] = true;
    for (int i = 0; i < n; i++) {
        if (connectionMatrix[city][i] == 1 && !visited[i]) {
            dfs(connectionMatrix, visited, n, i);
        }
    }
}

int countProvinces(int connectionMatrix[][MAX_N], int n) {
    bool visited[n];
    int provinces = 0;
    for (int i = 0; i < n; i++) {
        visited[i] = false;
    }
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            dfs(connectionMatrix, visited, n, i);
            provinces++;
        }
    }
    return provinces;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n;
        scanf("%d", &n);
        int connectionMatrix[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%d", &connectionMatrix[i][j]);
            }
        }
        printf("%d\n", countProvinces(connectionMatrix, n));
    }
    return 0;
}

