import java.util.Scanner;

public class Main {
    static final int MAX_N = 200;

    public static void dfs(int[][] connectionMatrix, boolean[] visited, int n, int city) {
        visited[city] = true;
        for (int i = 0; i < n; i++) {
            if (connectionMatrix[city][i] == 1 && !visited[i]) {
                dfs(connectionMatrix, visited, n, i);
            }
        }
    }

    public static int countProvinces(int[][] connectionMatrix, int n) {
        boolean[] visited = new boolean[n];
        int provinces = 0;
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                dfs(connectionMatrix, visited, n, i);
                provinces++;
            }
        }
        return provinces;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int n = scanner.nextInt();
            int[][] connectionMatrix = new int[n][n];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    connectionMatrix[i][j] = scanner.nextInt();
                }
            }
            System.out.println(countProvinces(connectionMatrix, n));
        }
    }
}

